"""Streamlit user interface for the smart resume screening system."""

import pandas as pd
import streamlit as st

from modules.database import (
    clear_all_candidates,
    initialize_database,
)
from modules.orchestrator import (
    get_saved_rankings,
    process_resume_batch,
)


st.set_page_config(
    page_title="Smart Resume Screening",
    page_icon="assets/logo.png",
    layout="wide",
)

st.markdown(
    """
    <style>
    [data-testid="stHeader"] {
    background: transparent;
}

    /* Layer the application above the decorative background. */
    .stApp {
        background:
            radial-gradient(
                circle at 8% 18%,
                rgba(25, 118, 210, 0.16),
                transparent 24rem
            ),
            radial-gradient(
                circle at 92% 30%,
                rgba(3, 169, 244, 0.13),
                transparent 26rem
            ),
            radial-gradient(
                circle at 50% 95%,
                rgba(13, 71, 161, 0.10),
                transparent 30rem
            );
    }

    /* Fixed AI-style circuit grid behind the Streamlit content. */
    .stApp::before {
        content: "";
        position: fixed;
        inset: 0;
        pointer-events: none;
        z-index: 0;
        opacity: 0.22;
        background-image:
            linear-gradient(
                rgba(30, 136, 229, 0.10) 1px,
                transparent 1px
            ),
            linear-gradient(
                90deg,
                rgba(30, 136, 229, 0.10) 1px,
                transparent 1px
            );
        background-size: 52px 52px;
        mask-image:
            linear-gradient(
                to bottom,
                black,
                transparent 82%
            );
    }

    /* Large project logo watermark on the left. */
    .stApp::after {
        content: "";
        position: fixed;
        left: -115px;
        top: 150px;
        width: 430px;
        height: 430px;
        pointer-events: none;
        z-index: 0;
        opacity: 0.075;
        background:
            url("data:image/png;base64,")
            center / contain no-repeat;
        filter: saturate(1.2);
    }

    .block-container {
        position: relative;
        z-index: 1;
        max-width: 1450px;
        padding-top: 1.5rem;
        padding-bottom: 3rem;
    }

    /* Decorative right-side resume screening illustration. */
    .resume-decoration {
        position: fixed;
        right: -70px;
        top: 330px;
        width: 290px;
        height: 360px;
        pointer-events: none;
        z-index: 0;
        opacity: 0.10;
        transform: rotate(5deg);
    }

    .resume-sheet {
        position: absolute;
        width: 185px;
        height: 245px;
        right: 55px;
        top: 35px;
        border: 3px solid #2196f3;
        border-radius: 16px;
        background:
            linear-gradient(
                rgba(33, 150, 243, 0.28) 0 0
            ) 28px 42px / 62px 10px no-repeat,
            repeating-linear-gradient(
                to bottom,
                rgba(33, 150, 243, 0.22) 0 7px,
                transparent 7px 20px
            ) 28px 82px / 125px 115px no-repeat;
    }

    .resume-sheet::before {
        content: "";
        position: absolute;
        width: 42px;
        height: 42px;
        left: 28px;
        top: 22px;
        border: 3px solid #2196f3;
        border-radius: 50%;
    }

    .resume-lens {
        position: absolute;
        width: 105px;
        height: 105px;
        right: 18px;
        bottom: 28px;
        border: 9px solid #2196f3;
        border-radius: 50%;
        box-sizing: border-box;
    }

    .resume-lens::after {
        content: "";
        position: absolute;
        width: 82px;
        height: 12px;
        right: -66px;
        bottom: -37px;
        border-radius: 10px;
        background: #2196f3;
        transform: rotate(46deg);
        transform-origin: left center;
    }

    /* Floating neural-network nodes. */
    .ai-nodes {
        position: fixed;
        left: 28px;
        bottom: 70px;
        width: 230px;
        height: 170px;
        pointer-events: none;
        z-index: 0;
        opacity: 0.12;
        background:
            radial-gradient(circle at 12% 25%, #29b6f6 0 6px, transparent 7px),
            radial-gradient(circle at 45% 8%, #29b6f6 0 6px, transparent 7px),
            radial-gradient(circle at 78% 28%, #29b6f6 0 6px, transparent 7px),
            radial-gradient(circle at 28% 72%, #29b6f6 0 6px, transparent 7px),
            radial-gradient(circle at 66% 82%, #29b6f6 0 6px, transparent 7px),
            linear-gradient(28deg, transparent 47%, #29b6f6 48% 50%, transparent 51%),
            linear-gradient(-24deg, transparent 47%, #29b6f6 48% 50%, transparent 51%);
    }

    .hero-card {
        padding: 1.4rem 1.6rem;
        border: 1px solid rgba(128, 128, 128, 0.20);
        border-radius: 18px;
        background: rgba(128, 128, 128, 0.06);
        margin-bottom: 1.2rem;
    }

    .section-card {
        padding: 1.2rem 1.3rem;
        border: 1px solid rgba(128, 128, 128, 0.18);
        border-radius: 16px;
        background: rgba(128, 128, 128, 0.035);
        margin-bottom: 1rem;
    }

    .section-label {
        font-size: 0.82rem;
        font-weight: 700;
        letter-spacing: 0.08em;
        text-transform: uppercase;
        opacity: 0.65;
        margin-bottom: 0.25rem;
    }

    .section-title {
        font-size: 1.55rem;
        font-weight: 700;
        margin-bottom: 0.2rem;
    }

    .section-subtitle {
        opacity: 0.72;
        margin-bottom: 1rem;
    }

    [data-testid="stMetric"] {
        background: rgba(128, 128, 128, 0.07);
        border: 1px solid rgba(128, 128, 128, 0.18);
        border-radius: 14px;
        padding: 1rem;
    }

    [data-testid="stFileUploader"] {
        border-radius: 14px;
    }

    div[data-testid="stExpander"] {
        border: 1px solid rgba(128, 128, 128, 0.20);
        border-radius: 14px;
        overflow: hidden;
        margin-bottom: 0.7rem;
    }

    .stButton > button,
    .stDownloadButton > button {
        border-radius: 10px;
        min-height: 44px;
        font-weight: 650;
    }

    .candidate-meta {
        padding: 0.75rem 0;
        opacity: 0.92;
    }

    .skill-box {
        padding: 0.8rem 1rem;
        border: 1px solid rgba(128, 128, 128, 0.18);
        border-radius: 12px;
        min-height: 90px;
        background: rgba(128, 128, 128, 0.04);
    }

    .muted {
        opacity: 0.68;
    }

    hr {
        margin-top: 1.5rem;
        margin-bottom: 1.5rem;
    }
    </style>
    """,
    unsafe_allow_html=True,
)

initialize_database()

# Decorative project-themed background elements.
st.markdown(
    """
    <div class="resume-decoration" aria-hidden="true">
        <div class="resume-sheet"></div>
        <div class="resume-lens"></div>
    </div>
    <div class="ai-nodes" aria-hidden="true"></div>
    """,
    unsafe_allow_html=True,
)


# Header
header_logo, header_text = st.columns(
    [1, 7],
    vertical_alignment="center",
)

with header_logo:
    st.image(
        "assets/logo.png",
        width=105,
    )

with header_text:
    st.markdown(
        """
        <div class="section-label">AI Recruitment Intelligence</div>
        """,
        unsafe_allow_html=True,
    )
    st.title("Smart Resume Screening System")
    st.caption(
        "Screen multiple resumes, compare candidate fit, "
        "rank applicants, and review screening history."
    )

st.divider()


# Screening workspace
st.markdown(
    """
    <div class="section-label">Screening Workspace</div>
    <div class="section-title">Job Requirements</div>
    <div class="section-subtitle">
        Define the role, add optional requirements, and upload resumes.
    </div>
    """,
    unsafe_allow_html=True,
)

input_column, upload_column = st.columns(
    [1.45, 1],
    gap="large",
)

with input_column:
    job_description = st.text_area(
        "Job Description",
        height=260,
        placeholder=(
            "Paste the complete job description here, including "
            "responsibilities, required skills, and role expectations."
        ),
    )

    requirement_one, requirement_two = st.columns(2)

    with requirement_one:
        required_experience = st.number_input(
            "Required Experience (Years)",
            min_value=0.0,
            max_value=50.0,
            value=0.0,
            step=0.5,
        )

    with requirement_two:
        required_education = st.text_input(
            "Required Education",
            placeholder="Example: MBA",
        )

    required_certifications_text = st.text_input(
        "Preferred Certifications",
        placeholder="Example: PMP, CAPM, PL-300",
    )

with upload_column:
    st.markdown(
        """
        <div class="section-card">
            <div class="section-label">Resume Batch</div>
            <div class="section-title">Upload Candidates</div>
            <div class="muted">
                Supported formats: PDF and DOCX. Multiple files are allowed.
            </div>
        </div>
        """,
        unsafe_allow_html=True,
    )

    uploaded_files = st.file_uploader(
        "Upload PDF or DOCX resumes",
        type=["pdf", "docx"],
        accept_multiple_files=True,
    )

    if uploaded_files:
        st.caption(
            f"{len(uploaded_files)} resume(s) ready for screening"
        )

    process_button = st.button(
        "Screen and Rank Candidates",
        type="primary",
        use_container_width=True,
    )


# Screening execution
if process_button:
    if not job_description.strip():
        st.error("Enter a job description before screening resumes.")

    elif not uploaded_files:
        st.error("Upload at least one PDF or DOCX resume.")

    else:
        required_certifications = [
            certification.strip()
            for certification in required_certifications_text.split(",")
            if certification.strip()
        ]

        resumes = [
            (
                uploaded_file.name,
                uploaded_file.getvalue(),
            )
            for uploaded_file in uploaded_files
        ]

        with st.spinner("Screening and ranking candidates..."):
            result = process_resume_batch(
                resumes=resumes,
                job_description=job_description,
                required_experience=required_experience,
                required_education=required_education,
                required_certifications=required_certifications,
            )

        ranked_candidates = result["ranked_candidates"]
        failed_resumes = result["failed_resumes"]

        status_one, status_two = st.columns(2)

        with status_one:
            if ranked_candidates:
                st.success(
                    f"{len(ranked_candidates)} candidate(s) "
                    "processed successfully."
                )
            else:
                st.warning(
                    "No candidates were processed successfully."
                )

        with status_two:
            if failed_resumes:
                st.error(
                    f"{len(failed_resumes)} resume(s) "
                    "could not be processed."
                )

        if failed_resumes:
            with st.expander("View Failed Resumes"):
                for failed_resume in failed_resumes:
                    st.write(
                        f"{failed_resume['file_name']}: "
                        f"{failed_resume['error']}"
                    )

        if ranked_candidates:
            st.divider()

            st.markdown(
                """
                <div class="section-label">Screening Results</div>
                <div class="section-title">Candidate Rankings</div>
                <div class="section-subtitle">
                    Candidates are ordered by final weighted score.
                </div>
                """,
                unsafe_allow_html=True,
            )

            for candidate in ranked_candidates:
                with st.expander(
                    f"Rank {candidate['rank']}  |  "
                    f"{candidate['name']}  |  "
                    f"{candidate['final_score']}/100",
                    expanded=candidate["rank"] == 1,
                ):
                    score_metric, experience_metric, skill_metric = (
                        st.columns(3)
                    )

                    with score_metric:
                        st.metric(
                            "Final Score",
                            f"{candidate['final_score']}/100",
                        )

                    with experience_metric:
                        st.metric(
                            "Experience",
                            (
                                f"{candidate['experience']} years"
                                if candidate["experience"] is not None
                                else "Not detected"
                            ),
                        )

                    with skill_metric:
                        st.metric(
                            "Skill Match",
                            f"{candidate['skill_score']}%",
                        )

                    progress_label, progress_score = st.columns(
                        [5, 1]
                    )

                    with progress_label:
                        st.write("Overall Match")

                    with progress_score:
                        st.write(
                            f"**{candidate['final_score']}%**"
                        )

                    st.progress(
                        min(
                            max(
                                candidate["final_score"] / 100,
                                0.0,
                            ),
                            1.0,
                        )
                    )

                    detail_one, detail_two = st.columns(2)

                    with detail_one:
                        st.write(
                            f"**File:** {candidate['file_name']}"
                        )
                        st.write(
                            f"**Email:** {candidate['email']}"
                        )
                        st.write(
                            f"**Phone:** {candidate['phone']}"
                        )

                    with detail_two:
                        st.write(
                            "**Education:** "
                            + (
                                ", ".join(candidate["education"])
                                if candidate["education"]
                                else "Not detected"
                            )
                        )
                        st.write(
                            "**Certifications:** "
                            + (
                                ", ".join(
                                    candidate["certifications"]
                                )
                                if candidate["certifications"]
                                else "None detected"
                            )
                        )

                    matched_column, missing_column = st.columns(2)

                    with matched_column:
                        st.markdown(
                            '<div class="skill-box">',
                            unsafe_allow_html=True,
                        )
                        st.write("**Matched Skills**")
                        st.write(
                            ", ".join(candidate["matched_skills"])
                            if candidate["matched_skills"]
                            else "None"
                        )
                        st.markdown(
                            "</div>",
                            unsafe_allow_html=True,
                        )

                    with missing_column:
                        st.markdown(
                            '<div class="skill-box">',
                            unsafe_allow_html=True,
                        )
                        st.write("**Missing Skills**")
                        st.write(
                            ", ".join(candidate["missing_skills"])
                            if candidate["missing_skills"]
                            else "None"
                        )
                        st.markdown(
                            "</div>",
                            unsafe_allow_html=True,
                        )


# Candidate history
st.divider()

st.markdown(
    """
    <div class="section-label">Analytics and Records</div>
    <div class="section-title">Candidate History</div>
    <div class="section-subtitle">
        Review saved screening records, filter results, and export data.
    </div>
    """,
    unsafe_allow_html=True,
)

saved_candidates = get_saved_rankings()

if saved_candidates:
    average_score = sum(
        candidate["final_score"]
        for candidate in saved_candidates
    ) / len(saved_candidates)

    highest_score = max(
        candidate["final_score"]
        for candidate in saved_candidates
    )

    top_candidate = saved_candidates[0]

    metric_one, metric_two, metric_three, metric_four = st.columns(4)

    with metric_one:
        st.metric(
            "Screening Records",
            len(saved_candidates),
        )

    with metric_two:
        st.metric(
            "Average Score",
            f"{average_score:.2f}/100",
        )

    with metric_three:
        st.metric(
            "Highest Score",
            f"{highest_score:.2f}/100",
        )

    with metric_four:
        st.metric(
            "Top Candidate",
            top_candidate["name"],
            f"{top_candidate['final_score']}/100",
        )

    st.write("")

    history_data = []

    for candidate in saved_candidates:
        history_data.append(
            {
                "Rank": candidate["rank"],
                "Candidate": candidate["name"],
                "File": candidate["file_name"],
                "Final Score": candidate["final_score"],
                "Skill Score": candidate["skill_score"],
                "Experience": (
                    candidate["experience"]
                    if candidate["experience"] is not None
                    else "Not detected"
                ),
                "Education": ", ".join(
                    candidate["education"]
                ),
                "Certifications": ", ".join(
                    candidate["certifications"]
                ),
            }
        )

    history_dataframe = pd.DataFrame(history_data)

    st.markdown("#### Find and Filter Records")

    search_column, score_column = st.columns(
        [1.5, 1],
        gap="large",
    )

    with search_column:
        search_query = st.text_input(
            "Search Candidate History",
            placeholder="Search by candidate name or file name",
        )

    with score_column:
        minimum_score = st.slider(
            "Minimum Final Score",
            min_value=0,
            max_value=100,
            value=0,
            step=1,
        )

    filtered_history_dataframe = history_dataframe.copy()

    if search_query.strip():
        normalized_query = search_query.strip().lower()

        filtered_history_dataframe = history_dataframe[
            history_dataframe["Candidate"]
            .astype(str)
            .str.lower()
            .str.contains(
                normalized_query,
                regex=False,
            )
            |
            history_dataframe["File"]
            .astype(str)
            .str.lower()
            .str.contains(
                normalized_query,
                regex=False,
            )
        ]

    filtered_history_dataframe = filtered_history_dataframe[
        filtered_history_dataframe["Final Score"]
        >= minimum_score
    ]

    sort_column_area, sort_order_area = st.columns(2)

    with sort_column_area:
        sort_column = st.selectbox(
            "Sort By",
            options=[
                "Rank",
                "Candidate",
                "Final Score",
                "Skill Score",
            ],
        )

    with sort_order_area:
        sort_order = st.radio(
            "Sort Order",
            options=[
                "Ascending",
                "Descending",
            ],
            horizontal=True,
        )

    filtered_history_dataframe = (
        filtered_history_dataframe.sort_values(
            by=sort_column,
            ascending=sort_order == "Ascending",
        )
    )

    st.caption(
        f"Showing {len(filtered_history_dataframe)} "
        f"of {len(history_dataframe)} screening record(s)"
    )

    if filtered_history_dataframe.empty:
        st.info(
            "No screening records match the current filters."
        )
    else:
        st.dataframe(
            filtered_history_dataframe,
            use_container_width=True,
            hide_index=True,
        )

    st.markdown("#### Export and Manage")

    export_one, export_two, clear_area = st.columns(3)

    csv_data = history_dataframe.to_csv(
        index=False
    ).encode("utf-8-sig")

    with export_one:
        st.download_button(
            label="Download Complete History",
            data=csv_data,
            file_name="candidate_screening_history.csv",
            mime="text/csv",
            use_container_width=True,
        )

    with export_two:
        if not filtered_history_dataframe.empty:
            filtered_csv_data = (
                filtered_history_dataframe.to_csv(
                    index=False
                ).encode("utf-8-sig")
            )

            st.download_button(
                label="Download Filtered Results",
                data=filtered_csv_data,
                file_name="filtered_candidate_results.csv",
                mime="text/csv",
                use_container_width=True,
            )

    with clear_area:
        if st.button(
            "Clear Candidate History",
            use_container_width=True,
        ):
            deleted_count = clear_all_candidates()

            st.success(
                f"{deleted_count} screening record(s) deleted."
            )

            st.rerun()

else:
    st.info(
        "No candidate screening history available. "
        "Process a resume to create the first record."
    )
